const i = items[0].json;
const chatId = i.chat_id;
const inst = String(i.instance || '1') === '2' ? '2' : '1';
const baseUrl = inst === '2' ? $env.GREEN_API_2_BASE_URL : $env.GREEN_API_1_BASE_URL;
const instanceId = inst === '2' ? $env.GREEN_API_2_INSTANCE_ID : $env.GREEN_API_1_INSTANCE_ID;
const token = inst === '2' ? $env.GREEN_API_2_TOKEN : $env.GREEN_API_1_TOKEN;
const sendUrl = `${baseUrl}/waInstance${instanceId}/sendMessage/${token}`;

const title = i.title || 'Validation requise';
const bodyText = i.body || '';
const opts = i.options || 'Reponds: OUI pour valider, NON pour annuler, ou ecris tes corrections.';
const message = `*${title}*\n\n${bodyText}\n\n_${opts}_`;
const bodyJson = JSON.stringify({ chatId, message });

const resumeUrl = $execution.resumeUrl;

const esc = (s) => String(s == null ? '' : s).replace(/'/g, "''");
const payload = JSON.stringify({ title, body: bodyText, step: i.step, project_id: i.project_id });
const sql = `INSERT INTO shared.hitl_approvals (chat_id, instance, project_id, theme, step, status, resume_url, payload) VALUES ('${esc(chatId)}', '${esc(inst)}', '${esc(i.project_id)}', '${esc(i.theme)}', '${esc(i.step)}', 'pending', '${esc(resumeUrl)}', '${esc(payload)}'::jsonb) RETURNING id;`;

return [{ json: { chatId, sendUrl, bodyJson, message, resumeUrl, sql, project_id: i.project_id, step: i.step } }];

const j = items[0].json || {};
const data = j.body || j;
const decision = String(data.decision || 'approved').toLowerCase();
const feedback = data.feedback || '';
return [{ json: { decision, feedback, approved: decision === 'approved' } }];
